<template>
	<view
		class="uv-tooltip"
		:style="[$uv.addStyle(customStyle)]"
	>
		<uv-overlay
			:show="showTooltip && tooltipTop !== -10000 && overlay && timeout>0"
			customStyle="backgroundColor: rgba(0, 0, 0, 0)"
			@click="overlayClickHandler"
		></uv-overlay>
		<view class="uv-tooltip__wrapper">
			<template v-if="isShow">
				<text
					class="uv-tooltip__wrapper__text"
					:id="textId"
					:ref="textId"
					:userSelect="false"
					:selectable="false"
					@click.stop="longpressHandler"
					:style="{
						color: color,
						backgroundColor: bgColor && showTooltip && tooltipTop !== -10000 ? bgColor : 'transparent'
					}"
				>{{ text }}</text>
			</template>
			<template v-else>
				<text
					class="uv-tooltip__wrapper__text"
					:id="textId"
					:ref="textId"
					:userSelect="false"
					:selectable="false"
					@longpress.stop="longpressHandler"
					:style="{
						color: color,
						backgroundColor: bgColor && showTooltip && tooltipTop !== -10000 ? bgColor : 'transparent'
					}"
				>{{ text }}</text>
			</template>
			<uv-transition
				mode="fade"
				:show="showTooltip"
				:duration="300"
				:customStyle="{
					position: 'absolute', 
					top: $uv.addUnit(tooltipTop),
					zIndex: zIndex,
					...tooltipStyle
				}"
			>
				<view
					class="uv-tooltip__wrapper__popup"
					:id="tooltipId"
					:ref="tooltipId"
				>
					<view
						class="uv-tooltip__wrapper__popup__indicator"
						hover-class="uv-tooltip__wrapper__popup__indicator--hover"
						v-if="showCopy || buttons.length"
						:style="[indicatorStyle, {
							width: $uv.addUnit(indicatorWidth),
							height: $uv.addUnit(indicatorWidth),
						}]"
					>
						<!-- з”ұдәҺnvueдёҚж”ҜжҢҒдёүи§’еҪўз»ҳеҲ¶пјҢиҝҷйҮҢе°ұеҒҡдёҖдёӘеӣӣж–№еҪўпјҢеҶҚж—ӢиҪ¬45degпјҢеҫ—еҲ°йңІеҮәзҡ„дёҖдёӘдёүи§’ -->
					</view>
					<view class="uv-tooltip__wrapper__popup__list">
						<view
							v-if="showCopy"
							class="uv-tooltip__wrapper__popup__list__btn"
							hover-class="uv-tooltip__wrapper__popup__list__btn--hover"
							@tap="setClipboardData"
						>
							<text
								class="uv-tooltip__wrapper__popup__list__btn__text"
							>еӨҚеҲ¶</text>
						</view>
						<uv-line
							direction="column"
							color="#8d8e90"
							v-if="showCopy && buttons.length > 0"
							length="18"
						></uv-line>
						<template v-for="(item , index) in buttons" :key="index">
							<view
								class="uv-tooltip__wrapper__popup__list__btn"
								hover-class="uv-tooltip__wrapper__popup__list__btn--hover"
							>
								<text
									class="uv-tooltip__wrapper__popup__list__btn__text"
									@tap="btnClickHandler(index)"
								>{{ item }}</text>
							</view>
							<uv-line
								direction="column"
								color="#8d8e90"
								v-if="index < buttons.length - 1"
								length="18"
							></uv-line>
						</template>
					</view>
				</view>
			</uv-transition>
		</view>
	</view>
</template>

<script lang="uts">
	import mpMixin from '@/uni_modules/uv-ui-tools/libs/mixin/mpMixin.js'
	import mixin from '@/uni_modules/uv-ui-tools/libs/mixin/mixin.js'
	import props from './props.js';



	/**
	 * Tooltip 
	 * @description 
	 * @tutorial https://www.uvui.cn/components/tooltip.html
	 * @property {String | Number}	text		йңҖиҰҒжҳҫзӨәзҡ„жҸҗзӨәж–Үеӯ—
	 * @property {String | Number}	copyText	зӮ№еҮ»еӨҚеҲ¶жҢүй’®ж—¶пјҢеӨҚеҲ¶зҡ„ж–Үжң¬пјҢдёәз©әеҲҷдҪҝз”ЁtextеҖј
	 * @property {String | Number}	size		ж–Үжң¬еӨ§е°ҸпјҲй»ҳи®Ө 14 пјү
	 * @property {String}			color		еӯ—дҪ“йўңиүІпјҲй»ҳи®Ө '#606266' пјү
	 * @property {String}			bgColor		еј№еҮәжҸҗзӨәжЎҶж—¶пјҢж–Үжң¬зҡ„иғҢжҷҜиүІпјҲй»ҳи®Ө 'transparent' пјү
	 * @property {String}			direction	еј№еҮәжҸҗзӨәзҡ„ж–№еҗ‘пјҢtop-дёҠж–№пјҢbottom-дёӢж–№пјҲй»ҳи®Ө 'top' пјү
	 * @property {String | Number}	zIndex		еј№еҮәжҸҗзӨәзҡ„z-indexпјҢnvueж— ж•ҲпјҲй»ҳи®Ө 10071 пјү
	 * @property {Boolean}			showCopy	жҳҜеҗҰжҳҫзӨәеӨҚеҲ¶жҢүй’®пјҲй»ҳи®Ө true пјү
	 * @property {Array}			buttons		жү©еұ•зҡ„жҢүй’®з»„
	 * @property {Boolean}			overlay		жҳҜеҗҰжҳҫзӨәйҖҸжҳҺйҒ®зҪ©д»ҘйҳІжӯўи§Ұж‘ёз©ҝйҖҸпјҲй»ҳи®Ө true пјү
	 * @property {Object}			customStyle	е®ҡд№үйңҖиҰҒз”ЁеҲ°зҡ„еӨ–йғЁж ·ејҸ
	 * 
	 * @event {Function} 
	 * @example 
	 */
	export default {
		name: 'uv-tooltip',
		emits: ['click'],
		mixins: [mpMixin, mixin, props],
		data() {
			return {
				// жҳҜеҗҰеұ•зӨәж°”жіЎ
				showTooltip: true,
				// з”ҹжҲҗе”ҜдёҖidпјҢйҳІжӯўдёҖдёӘйЎөйқўеӨҡдёӘз»„д»¶пјҢйҖ жҲҗе№Іжү°
				textId: '',
				tooltipId: '',
				// еҲқе§Ӣж—¶з”ҡиҮідёәеҫҲеӨ§зҡ„еҖјпјҢи®©е…¶з§»еҲ°еұҸе№•еӨ–йқўпјҢдёәдәҶи®Ўз®—е…ғзҙ зҡ„е°әеҜё
				tooltipTop: -10000,
				// ж°”жіЎзҡ„дҪҚзҪ®дҝЎжҒҜ
				tooltipInfo: {
					width: 0,
					left: 0
				},
				// ж–Үжң¬зҡ„дҪҚзҪ®дҝЎжҒҜ
				textInfo: {
					width: 0,
					left: 0
				},
				// дёүи§’еҪўжҢҮзӨәеҷЁзҡ„ж ·ејҸ
				indicatorStyle: {},
				// ж°”жіЎеңЁеҸҜиғҪи¶…еҮәеұҸе№•иҫ№жІҝиҢғеӣҙж—¶пјҢйҮҚж–°е®ҡдҪҚеҗҺпјҢи·қзҰ»еұҸе№•иҫ№жІҝзҡ„и·қзҰ»
				screenGap: 12,
				// дёүи§’еҪўжҢҮзӨәеҷЁзҡ„е®Ҫй«ҳпјҢз”ұдәҺеҜ№е…ғзҙ иҝӣиЎҢдәҶи§’еәҰж—ӢиҪ¬пјҢзІҫзЎ®и®Ўз®—жҢҮзӨәеҷЁдҪҚзҪ®ж—¶пјҢйңҖиҰҒз”ЁеҲ°е…¶е°әеҜёдҝЎжҒҜ
				indicatorWidth: 14,
				timeout: 0
			}
		},
		watch: {
			propsChange() {
				this.getElRect()
			},
			showTooltip(newVal){
				if(!newVal) this.timeout = 0;
			}
		},
		computed: {
			isShow(){
				const isPC = this.$uv.sys()?.model == 'PC';
				if(isPC) {
					return true;
				}

				return false;

				return true;
			},
			// зү№еҲ«еӨ„зҗҶH5зҡ„еӨҚеҲ¶пјҢеӣ дёәH5жөҸи§ҲеҷЁжҳҜиҮӘеёҰзі»з»ҹеӨҚеҲ¶еҠҹиғҪзҡ„пјҢеңЁH5зҺҜеўғ
			// еҪ“дёҖдәӣдҫқиө–еҸӮж•°еҸҳеҢ–ж—¶пјҢйңҖиҰҒйҮҚж–°и®Ўз®—ж°”жіЎе’ҢжҢҮзӨәеҷЁзҡ„дҪҚзҪ®дҝЎжҒҜ
			propsChange() {
				return [this.text, this.buttons]
			},
			// и®Ўз®—ж°”жіЎе’ҢжҢҮзӨәеҷЁзҡ„дҪҚзҪ®дҝЎжҒҜ
			tooltipStyle() {
				const style = {};
				if (this.tooltipInfo.width / 2 > this.textInfo.left + this.textInfo.width / 2 - this.screenGap) {
					this.indicatorStyle = {}
					style.left = `-${this.$uv.addUnit(this.textInfo.left - this.screenGap)}`
					this.indicatorStyle.left = this.$uv.addUnit(this.textInfo.width / 2 - this.$uv.getPx(style.left) - this.indicatorWidth /
						2)
				} else if (this.tooltipInfo.width / 2 > this.$uv.sys().windowWidth - this.textInfo.right + this.textInfo.width / 2 -
					this.screenGap) {
					this.indicatorStyle = {}
					style.right = `-${this.$uv.addUnit(this.$uv.sys().windowWidth - this.textInfo.right - this.screenGap)}`
					this.indicatorStyle.right = this.$uv.addUnit(this.textInfo.width / 2 - this.$uv.getPx(style.right) - this
						.indicatorWidth / 2)
				} else {
					const left = Math.abs(this.textInfo.width / 2 - this.tooltipInfo.width / 2)
					style.left = this.textInfo.width > this.tooltipInfo.width ? this.$uv.addUnit(left) : -this.$uv.addUnit(left)
					this.indicatorStyle = {}
				}
				if (this.direction === 'top') {
					style.marginTop = `-${10 + this.tooltipInfo.height}px`
					this.indicatorStyle.bottom = '-4px'
				} else {
					style.marginTop = `${this.tooltipInfo.height-10}px`
					this.indicatorStyle.top = '-4px'
				}
				return style
			}
		},
		created() {
			this.textId = this.$uv.guid();
			this.tooltipId = this.$uv.guid();
		},
		mounted() {
			this.init()
		},
		methods: {
			init() {
				this.getElRect()
			},
			// й•ҝжҢүи§ҰеҸ‘дәӢд»¶
			async longpressHandler(e) {
				this.tooltipTop = 0
				this.showTooltip = true
				setTimeout(()=>{
					this.timeout = 1;
				},300)
			},
			// зӮ№еҮ»йҖҸжҳҺйҒ®зҪ©
			overlayClickHandler() {
				this.showTooltip = false
			},
			// зӮ№еҮ»еј№еҮәжҢүй’®
			btnClickHandler(index) {
				this.showTooltip = false
				// еҰӮжһңйңҖиҰҒеұ•зӨәеӨҚеҲ¶жҢүй’®пјҢжӯӨеӨ„indexйңҖиҰҒеҠ 1пјҢеӣ дёәеӨҚеҲ¶жҢүй’®еңЁз¬¬дёҖдёӘдҪҚзҪ®
				this.$emit('click', this.showCopy ? index + 1 : index)
			},
			// жҹҘиҜўеҶ…е®№й«ҳеәҰ
			queryRect(ref) {

				// з»„д»¶еҶ…йғЁдёҖиҲ¬з”Ёthis.$uvGetRectпјҢеҜ№еӨ–зҡ„дёәgetRectпјҢдәҢиҖ…еҠҹиғҪдёҖиҮҙпјҢеҗҚз§°дёҚеҗҢ
				return new Promise(resolve => {
					this.$uvGetRect(`#${ref}`).then(size => {
						resolve(size)
					})
				})











			},
			// е…ғзҙ е°әеҜё
			getElRect() {
				// и°ғз”Ёд№ӢеүҚпјҢе…Ҳе°ҶжҢҮзӨәеҷЁи°ғж•ҙеҲ°еұҸе№•еӨ–пјҢж–№дҫҝиҺ·еҸ–е°әеҜё
				this.showTooltip = true
				this.tooltipTop = -10000
				this.$uv.sleep(500).then(() => {
					this.queryRect(this.tooltipId).then(size => {
						this.tooltipInfo = size
						// иҺ·еҸ–ж°”жіЎе°әеҜёд№ӢеҗҺпјҢе°Ҷе…¶йҡҗи—ҸпјҢдёәдәҶи®©дёӢж¬ЎеҲҮжҚўж°”жіЎжҳҫзӨәдёҺйҡҗи—Ҹж—¶пјҢжңүж·Ўе…Ҙж·ЎеҮәзҡ„ж•Ҳжһң
						this.showTooltip = false
					})
					this.queryRect(this.textId).then(size => {
						this.textInfo = size
					})
				})
			},
			// еӨҚеҲ¶ж–Үжң¬еҲ°зІҳиҙҙжқҝ
			setClipboardData() {
				// е…ій—ӯз»„д»¶
				this.showTooltip = false
				this.$emit('click', 0)
				uni.setClipboardData({
					// дјҳе…ҲдҪҝз”ЁcopyTextеӯ—ж®өпјҢеҰӮжһңжІЎжңүпјҢеҲҷй»ҳи®ӨдҪҝз”Ёtextеӯ—ж®өеҪ“еҒҡеӨҚеҲ¶зҡ„еҶ…е®№
					data: this.copyText || this.text,
					success: () => {
						this.showToast && this.$uv.toast('еӨҚеҲ¶жҲҗеҠҹ')
					},
					fail: () => {
						this.showToast && this.$uv.toast('еӨҚеҲ¶еӨұиҙҘ')
					},
					complete: () => {
						this.showTooltip = false
					}
				})
			}
		}
	}
</script>

<style lang="scss" scoped>
	@import '@/uni_modules/uv-ui-tools/libs/css/components.scss';

	.uv-tooltip {
		position: relative;
		@include flex;

		&__wrapper {
			@include flex;
			justify-content: center;

			white-space: nowrap;


			&__text {
				font-size: 14px;
			}

			&__popup {
				@include flex;
				justify-content: center;

				&__list {
					background-color: #060607;
					position: relative;
					flex: 1;
					border-radius: 5px;
					padding: 0px 0;
					@include flex(row);
					align-items: center;
					overflow: hidden;

					&__btn {
						padding: 11px 13px;

						&--hover {
							background-color: #58595B;
						}

						&__text {
							line-height: 12px;
							font-size: 13px;
							color: #FFFFFF;
						}
					}
				}

				&__indicator {
					position: absolute;
					background-color: #060607;
					width: 14px;
					height: 14px;
					bottom: -4px;
					transform: rotate(45deg);
					border-radius: 2px;
					z-index: -1;

					&--hover {
						background-color: #58595B;
					}
				}
			}
		}
	}
</style>
